/**
 * KPI cards row for the Run Analytics dashboard (warren-638a /
 * pl-ad0f step 5).
 *
 * Renders the `totals` envelope from `GET /analytics/runs` as a grid of
 * compact stat cards: total runs (with terminal-state breakdown),
 * success rate, median + p95 duration, median + total context tokens,
 * and total + avg cost. Each card degrades to an em-dash while the
 * query is loading or when the metric's sample is empty (null), so the
 * grid never collapses.
 */
import type { RunAnalyticsTotals } from "@/api/client.ts";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card.tsx";
import {
	formatCostUsd,
	formatCount,
	formatDurationMs,
	formatRate,
	formatTokensOrDash,
} from "./format.ts";

function KpiCard({
	title,
	value,
	hint,
}: {
	title: string;
	value: React.ReactNode;
	hint?: React.ReactNode;
}) {
	return (
		<Card>
			<CardHeader className="pb-3">
				<CardTitle className="text-xs font-medium text-(--color-muted-foreground)">
					{title}
				</CardTitle>
			</CardHeader>
			<CardContent>
				<div className="font-mono text-2xl">{value}</div>
				{hint !== undefined ? (
					<p className="mt-1 text-xs text-(--color-muted-foreground)">{hint}</p>
				) : null}
			</CardContent>
		</Card>
	);
}

export function KpiCards({ totals }: { totals: RunAnalyticsTotals | undefined }) {
	const loading = totals === undefined;
	const dash = "â€”";

	return (
		<div className="grid grid-cols-2 gap-4 md:grid-cols-3 lg:grid-cols-4">
			<KpiCard
				title="Runs"
				value={loading ? dash : totals.runs.toLocaleString()}
				hint={
					loading
						? undefined
						: `${totals.succeeded} ok Â· ${totals.failed} fail Â· ${totals.cancelled} cxl Â· ${totals.active} active`
				}
			/>
			<KpiCard
				title="Success rate"
				value={loading ? dash : formatRate(totals.successRate)}
				hint={loading ? undefined : `${totals.succeeded} of terminal runs`}
			/>
			<KpiCard
				title="Median duration"
				value={loading ? dash : formatDurationMs(totals.durationMs.median)}
				hint={loading ? undefined : `p95 ${formatDurationMs(totals.durationMs.p95)}`}
			/>
			<KpiCard
				title="Median context"
				value={loading ? dash : formatTokensOrDash(totals.contextTokens.median)}
				hint={
					loading
						? undefined
						: `avg ${formatTokensOrDash(totals.contextTokens.avg)} Â· ${totals.contextTokens.count} priced`
				}
			/>
			<KpiCard
				title="Total cost"
				value={loading ? dash : formatCostUsd(totals.cost.total)}
				hint={
					loading
						? undefined
						: `avg ${totals.cost.avg === null ? dash : formatCostUsd(totals.cost.avg)} Â· ${totals.cost.priced} priced`
				}
			/>
			<KpiCard
				title="Active runs"
				value={loading ? dash : formatCount(totals.active)}
				hint={loading ? undefined : "currently non-terminal"}
			/>
		</div>
	);
}

/**
 * Per-agent / per-model rollup tables for the Run Analytics dashboard
 * (warren-638a / pl-ad0f step 5).
 *
 * Both dimensions share the `RunGroupBucket` wire shape, so one
 * `GroupTable` renders either. Buckets are pre-sorted server-side by
 * context desc; the null group key (`RUN_ANALYTICS_NONE_KEY`) renders
 * as an em-dash. Agent rows deep-link to `/agents/:name`; model rows
 * are plain monospace (no agents-by-model route in the UI).
 */
import { Link } from "react-router-dom";
import { RUN_ANALYTICS_NONE_KEY, type RunGroupBucket } from "@/api/client.ts";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card.tsx";
import {
	Table,
	TableBody,
	TableCell,
	TableHead,
	TableHeader,
	TableRow,
} from "@/components/ui/table.tsx";
import { formatCostUsd, formatDurationMs, formatRate, formatTokensOrDash } from "./format.ts";

function renderKey(dimension: "agent" | "model", key: string): React.ReactNode {
	if (key === RUN_ANALYTICS_NONE_KEY) {
		return <span className="text-(--color-muted-foreground)">â€”</span>;
	}
	if (dimension === "agent") {
		return (
			<Link
				to={`/agents/${encodeURIComponent(key)}`}
				className="underline-offset-2 hover:underline"
			>
				{key}
			</Link>
		);
	}
	return <span className="font-mono text-xs">{key}</span>;
}

export function GroupTable({
	title,
	subtitle,
	dimension,
	buckets,
	loading,
}: {
	title: string;
	subtitle: string;
	dimension: "agent" | "model";
	buckets: RunGroupBucket[];
	loading: boolean;
}) {
	return (
		<Card>
			<CardHeader>
				<CardTitle className="text-base">{title}</CardTitle>
				<p className="text-xs text-(--color-muted-foreground)">{subtitle}</p>
			</CardHeader>
			<CardContent>
				{loading ? (
					<p className="text-sm text-(--color-muted-foreground)">Loadingâ€¦</p>
				) : buckets.length === 0 ? (
					<p className="text-sm text-(--color-muted-foreground)">No data in this window.</p>
				) : (
					<Table>
						<TableHeader>
							<TableRow>
								<TableHead>{dimension === "agent" ? "Agent" : "Model"}</TableHead>
								<TableHead className="text-right">Runs</TableHead>
								<TableHead className="text-right">Success</TableHead>
								<TableHead className="text-right">Avg ctx</TableHead>
								<TableHead className="text-right">Avg dur</TableHead>
								<TableHead className="text-right">Cost</TableHead>
							</TableRow>
						</TableHeader>
						<TableBody>
							{buckets.map((b) => (
								<TableRow key={b.key}>
									<TableCell className="max-w-[260px] truncate">
										{renderKey(dimension, b.key)}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs text-(--color-muted-foreground)">
										{b.runs}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs">
										{formatRate(b.successRate)}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs">
										{formatTokensOrDash(b.avgContextTokens)}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs text-(--color-muted-foreground)">
										{formatDurationMs(b.avgDurationMs)}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs">
										{formatCostUsd(b.costUsd)}
									</TableCell>
								</TableRow>
							))}
						</TableBody>
					</Table>
				)}
			</CardContent>
		</Card>
	);
}

/**
 * Run analytics view â€” Phase 1 (warren-638a / pl-ad0f step 5) + Phase 2
 * (warren-436a / pl-ad0f step 10).
 *
 * Operator dashboard over `runs` execution telemetry, complementing the
 * spend-focused Cost analytics page. Renders a date-range / project
 * filter, a row of KPI cards (`totals`), four recharts visualizations
 * (runs-over-time, avg-context-per-agent, top-seeds-by-context,
 * failure-reason), and per-agent / per-model rollup tables â€” all from a
 * single `GET /analytics/runs` round-trip (`runAnalyticsApi.runs`).
 *
 * Phase 2 layers in a second `GET /analytics/behavior` round-trip
 * (`runAnalyticsApi.behavior`): severity-coded insight callout cards at
 * the top, a command-by-category bar chart, and the stuck-command
 * leaderboard table with os-eco highlighting. The behavior query is
 * independent so the fast run-level view renders without waiting on the
 * heavier event-trace scan.
 *
 * Filter state persists in the URL hash query via react-router's
 * `useSearchParams` so deep links survive a refresh, mirroring the Cost
 * analytics page. The chart + table sub-components live under
 * `run-analytics/` to keep this page and each child under the 500-line
 * file budget (warren-4553).
 */
import { useQuery } from "@tanstack/react-query";
import { useSearchParams } from "react-router-dom";
import { projectsApi, runAnalyticsApi } from "@/api/client.ts";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card.tsx";
import { PageHeader } from "@/components/ui/page-header.tsx";
import {
	AvgContextPerAgentChart,
	FailureReasonChart,
	RunsOverTimeChart,
	TopSeedsByContextChart,
} from "./run-analytics/Charts.tsx";
import { CommandCategoryChart, StuckCommandTable } from "./run-analytics/CommandMining.tsx";
import { TokenConsumptionChart } from "./run-analytics/TokenConsumptionChart.tsx";
import { InsightCallouts } from "./run-analytics/Insights.tsx";
import { KpiCards } from "./run-analytics/KpiCards.tsx";
import { GroupTable } from "./run-analytics/Tables.tsx";

/** Default date window: last 30 days. Mirrors the server default. */
function defaultFrom(): string {
	const d = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
	return d.toISOString().slice(0, 10);
}

export function RunAnalyticsPage() {
	const [searchParams, setSearchParams] = useSearchParams();
	const projectId = searchParams.get("projectId") ?? "";
	const from = searchParams.get("from") ?? defaultFrom();
	const to = searchParams.get("to") ?? "";

	const updateParam = (k: string, v: string) => {
		const next = new URLSearchParams(searchParams);
		if (v === "") next.delete(k);
		else next.set(k, v);
		setSearchParams(next, { replace: true });
	};

	const projects = useQuery({
		queryKey: ["projects"],
		queryFn: ({ signal }) => projectsApi.list(signal),
	});

	const analytics = useQuery({
		queryKey: ["analytics", "runs", { projectId, from, to }],
		queryFn: ({ signal }) =>
			runAnalyticsApi.runs(
				{
					...(projectId !== "" ? { projectId } : {}),
					...(from !== "" ? { from: `${from}T00:00:00.000Z` } : {}),
					...(to !== "" ? { to: `${to}T23:59:59.999Z` } : {}),
				},
				signal,
			),
	});

	const behavior = useQuery({
		queryKey: ["analytics", "behavior", { projectId, from, to }],
		queryFn: ({ signal }) =>
			runAnalyticsApi.behavior(
				{
					...(projectId !== "" ? { projectId } : {}),
					...(from !== "" ? { from: `${from}T00:00:00.000Z` } : {}),
					...(to !== "" ? { to: `${to}T23:59:59.999Z` } : {}),
				},
				signal,
			),
	});

	const data = analytics.data;
	const loading = analytics.isLoading;
	const behaviorData = behavior.data;

	return (
		<div className="space-y-6">
			<PageHeader
				title="Run analytics"
				description="Execution telemetry across runs â€” success, duration, context burn. Defaults to the last 30 days."
			/>

			<Card>
				<CardHeader>
					<CardTitle>Filters</CardTitle>
				</CardHeader>
				<CardContent>
					<div className="flex flex-wrap items-end gap-4">
						<div className="flex flex-col gap-1">
							<label htmlFor="ra-from" className="text-xs text-(--color-muted-foreground)">
								From
							</label>
							<input
								id="ra-from"
								type="date"
								value={from}
								onChange={(e) => updateParam("from", e.target.value)}
								className="rounded border border-(--color-border) bg-transparent px-2 py-1 text-sm"
							/>
						</div>
						<div className="flex flex-col gap-1">
							<label htmlFor="ra-to" className="text-xs text-(--color-muted-foreground)">
								To
							</label>
							<input
								id="ra-to"
								type="date"
								value={to}
								onChange={(e) => updateParam("to", e.target.value)}
								className="rounded border border-(--color-border) bg-transparent px-2 py-1 text-sm"
							/>
						</div>
						<div className="flex flex-col gap-1">
							<label htmlFor="ra-project" className="text-xs text-(--color-muted-foreground)">
								Project
							</label>
							<select
								id="ra-project"
								value={projectId}
								onChange={(e) => updateParam("projectId", e.target.value)}
								className="rounded border border-(--color-border) bg-transparent px-2 py-1 text-sm"
							>
								<option value="">All projects</option>
								{projects.data?.projects.map((p) => (
									<option key={p.id} value={p.id}>
										{p.gitUrl.replace(/^https:\/\/github\.com\//, "") || p.id}
									</option>
								))}
							</select>
						</div>
					</div>
				</CardContent>
			</Card>

			{analytics.isError ? (
				<Card>
					<CardContent className="py-6 text-sm text-(--color-destructive)">
						Failed to load run analytics.{" "}
						{(analytics.error as Error | null)?.message ?? ""}
					</CardContent>
				</Card>
			) : null}

			<InsightCallouts insights={behaviorData?.insights ?? []} />

			<KpiCards totals={data?.totals} />

			<div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
				<RunsOverTimeChart timeSeries={data?.timeSeries ?? []} />
				<FailureReasonChart byFailureReason={data?.byFailureReason ?? []} />
				<AvgContextPerAgentChart byAgent={data?.byAgent ?? []} />
				<TopSeedsByContextChart topSeeds={data?.topSeedsByContext ?? []} />
			</div>

			<div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
				<GroupTable
					title="By agent"
					subtitle="Run rollup per agent"
					dimension="agent"
					buckets={data?.byAgent ?? []}
					loading={loading}
				/>
				<GroupTable
					title="By model"
					subtitle="Run rollup per provider model"
					dimension="model"
					buckets={data?.byModel ?? []}
					loading={loading}
				/>
			</div>

			{behavior.isError ? (
				<Card>
					<CardContent className="py-6 text-sm text-(--color-destructive)">
						Failed to load command behavior.{" "}
						{(behavior.error as Error | null)?.message ?? ""}
					</CardContent>
				</Card>
			) : null}

			{data ? (
				<TokenConsumptionChart
					timeSeries={data.tokens.timeSeries}
					byModelTimeSeries={data.tokens.byModelTimeSeries}
					byProviderTimeSeries={data.tokens.byProviderTimeSeries}
				/>
			) : null}

			<div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
				<CommandCategoryChart byCategory={behaviorData?.mining.byCategory ?? []} />
				<StuckCommandTable byStuckScore={behaviorData?.mining.byStuckScore ?? []} />
			</div>
		</div>
	);
}

